              {t.image_url ? (
                // eslint-disable-next-line @next/next/no-img-element
                <img
                  src={String(t.image_url)}
                  alt={title}
                  className="h-[360px] w-full object-contain"
                  loading="lazy"
                />
              ) : (
                <div className="p-6 text-sm text-neutral-700">No image</div>
              )}
            </div>
          </div>

